	(1812,'_transient_dash_3605f57d6641b1f6504fce9d39bcf566','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2017/08/wordpress-4-8-1-maintenance-release/\'>WordPress 4.8.1 Maintenance Release</a> <span class=\"rss-date\">2 agosto, 2017</span><div class=\"rssSummary\">After over 13 million downloads of WordPress 4.8, we are pleased to announce the immediate availability of WordPress 4.8.1, a maintenance release. This release contains 29 maintenance fixes and enhancements, chief among them are fixes to the rich Text widget and the introduction of the Custom HTML widget. For a full list of changes, consult the release [&hellip;]</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wptavern.com/trademark-trial-and-appeal-board-dismisses-automattics-trademark-dispute-against-chris-pearson\'>WPTavern: Trademark Trial and Appeal Board Dismisses Automattic’s Trademark Dispute Against Chris Pearson</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/in-case-you-missed-it-issue-22\'>WPTavern: In Case You Missed It – Issue 22</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/publishers-are-moving-back-to-wordpress-after-short-experiments-with-medium\'>WPTavern: Publishers Are Moving Back to WordPress After Short Experiments with Medium</a></li></ul></div><div class=\"rss-widget\"><ul></ul></div>','no'),
