	(731,202,'repeatable_fields_2','a:3:{i:0;a:5:{s:13:\"texto_espanol\";s:60:\"la esposa de Ahan(?) cose, [el pronóstico es] alimento (?).\";s:6:\"img_hp\";s:7:\"3_1.png\";s:10:\"texto_maya\";s:39:\"<i>uchuy yat[a]n Ahan(?), o\'och(?)</i>.\";s:12:\"coordenada_x\";s:3:\"221\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:89:\"la esposa de Itzamna\' Kokaaj regala, [el pronóstico son] 16 crepúsculos vespertinos(?).\";s:6:\"img_hp\";s:7:\"3_2.png\";s:10:\"texto_maya\";s:61:\"<i>uchu\'w yat[a]n Itzamn[a\'] Kokaaj, waklaju\'n ook\'in(?)</i>.\";s:12:\"coordenada_x\";s:3:\"406\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:48:\"la esposa de Wak Tzeen(?) cose, es su mortandad.\";s:6:\"img_hp\";s:7:\"3_3.png\";s:10:\"texto_maya\";s:45:\"<i>uchuy yat[a]n Wak Tzeen(?), ucham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"610\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
