	(819,208,'id_notas','      <p>Una nueva columna de cinco signos días, acompañados por el coeficiente rojo 12, da comienzo a un almanaque nuevo, que concluye en la página 6c.</p>'),
	(820,208,'id_tematica','Almanaques misceláneos serie II'),
	(821,210,'_post_template','Seccion_Hotspot_A.php'),
	(822,210,'id_correo',NULL),
