	(999,206,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:66:\"[el dios] K\'in Ajaw consideró su palabra, [el augurio es]malo(?).\";s:6:\"img_hp\";s:7:\"9_1.png\";s:10:\"texto_maya\";s:38:\"<i>utum uchich K\'in Ajaw, k\'as(?).</i>\";s:12:\"coordenada_x\";s:3:\"161\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:65:\"[el dios] Itzamna\' Kokaaj de las pepitas(?) deliberó su palabra.\";s:6:\"img_hp\";s:7:\"9_2.png\";s:10:\"texto_maya\";s:49:\"<i>utum uchich Itzamna[\'] Kokaaj saak[i]l(?).</i>\";s:12:\"coordenada_x\";s:3:\"295\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:56:\"[el dios] Ik\'(?) ordenó su palabra, es su atardecer(?).\";s:6:\"img_hp\";s:7:\"9_3.png\";s:10:\"texto_maya\";s:37:\"<i>utum uchich Ik\'(?) yook\'in(?).</i>\";s:12:\"coordenada_x\";s:3:\"425\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:65:\"[el dios] Kiimil deliberó su palabra, [el augurio es] mortandad.\";s:6:\"img_hp\";s:7:\"9_4.png\";s:10:\"texto_maya\";s:40:\"<i>utum[aj] uchich Kiimil, cham[a]l.</i>\";s:12:\"coordenada_x\";s:3:\"555\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1000,207,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:86:\"[el dios] Buluk Kab(?) taladró su palabra, [el augurio es] señores puestos en orden.\";s:10:\"texto_maya\";s:45:\"<i>joch\' uchich Buluk Kab(?), tz\'ak ajaw.</i>\";s:6:\"img_hp\";s:8:\"10_1.png\";s:12:\"coordenada_x\";s:3:\"143\";s:12:\"coordenada_y\";s:2:\"10\";}i:1;a:5:{s:13:\"texto_espanol\";s:52:\"[el dios] Ahkan, taladró su palabra, es su anuncio.\";s:10:\"texto_maya\";s:34:\"<i>joch\' uchich Ahkan, umu\'uk.</i>\";s:6:\"img_hp\";s:8:\"10_2.png\";s:12:\"coordenada_x\";s:3:\"277\";s:12:\"coordenada_y\";s:2:\"10\";}i:2;a:5:{s:13:\"texto_espanol\";s:64:\"[el dios] Itzamna\' Kokaaj de las pepitas(?) taladró su palabra.\";s:10:\"texto_maya\";s:50:\"<i>joch\' uchich Itzamna[\'] Kokaaj saak[i]l(?).</i>\";s:6:\"img_hp\";s:8:\"10_3.png\";s:12:\"coordenada_x\";s:3:\"439\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:76:\"[el dios] Jun Lajun Talaan taladró su palabra, [el pronóstico es] ruin(?).\";s:10:\"texto_maya\";s:51:\"<i>ujoch\'a[j] uchich Jun Lajun Talaan, k\'as(?).</i>\";s:6:\"img_hp\";s:8:\"10_4.png\";s:12:\"coordenada_x\";s:3:\"581\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1001,208,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:82:\"es el alimento de Itzamna´Kokaaj de las pepitas(?), [el augurio es] mucha comida.\";s:10:\"texto_maya\";s:55:\"<i>o\'och Itzamna[\'] Kokaaj saak[i]l(?), ox wi\'[il].</i>\";s:6:\"img_hp\";s:8:\"11_1.png\";s:12:\"coordenada_x\";s:3:\"138\";s:12:\"coordenada_y\";s:2:\"20\";}i:1;a:5:{s:13:\"texto_espanol\";s:50:\"es el alimento de Kiimil, mortandad es su anuncio.\";s:10:\"texto_maya\";s:38:\"<i>o\'och Kiimil, cham[a]l, umu\'uk.</i>\";s:6:\"img_hp\";s:8:\"11_2.png\";s:12:\"coordenada_x\";s:3:\"265\";s:12:\"coordenada_y\";s:2:\"20\";}i:2;a:5:{s:13:\"texto_espanol\";s:55:\"[es el alimento (?) de K\'uh, señorío es su atardecer.\";s:10:\"texto_maya\";s:44:\"<i>o\'och(?) K\'uh, ajawle[l], yook\'in(?).</i>\";s:6:\"img_hp\";s:8:\"11_3.png\";s:12:\"coordenada_x\";s:3:\"442\";s:12:\"coordenada_y\";s:1:\"5\";}i:3;a:5:{s:13:\"texto_espanol\";s:61:\"es el alimento(?) de Jun Lajun Talaan, ruin(?) es su anuncio.\";s:10:\"texto_maya\";s:49:\"<i>o\'och(?) Jun Lajun Talaan, k\'as(?) umu\'uk.</i>\";s:6:\"img_hp\";s:8:\"11_4.png\";s:12:\"coordenada_x\";s:3:\"580\";s:12:\"coordenada_y\";s:1:\"5\";}}'),
	(1002,210,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:69:\"la palabra del [dios Ahan(?)] comienza, [el augurio es] mucha comida.\";s:6:\"img_hp\";s:8:\"12_1.png\";s:10:\"texto_maya\";s:40:\"<i>tz\'un uchich Ahan(?), ox wi\'[il].</i>\";s:12:\"coordenada_x\";s:3:\"130\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:65:\"la palabra del [dios] Kiimil comienza, [el augurio es] mortandad.\";s:6:\"img_hp\";s:8:\"12_2.png\";s:10:\"texto_maya\";s:36:\"<i>tz\'un uchich Kiimil cham[a]l.</i>\";s:12:\"coordenada_x\";s:3:\"257\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:65:\"la palabra del [dios] Itzamna\' Kokaaj de las pepitas(\') comienza.\";s:6:\"img_hp\";s:8:\"12_3.png\";s:10:\"texto_maya\";s:51:\"<i>tz\'un uchich Itzamna[\'] Kokaaj, saak[i]l(?).</i>\";s:12:\"coordenada_x\";s:3:\"406\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:57:\"la palabra del [dios] Yaax Bolon comienza, es su anuncio.\";s:6:\"img_hp\";s:8:\"12_4.png\";s:10:\"texto_maya\";s:38:\"<i>tz\'un uchich Yaax Bolon umu\'uk.</i>\";s:12:\"coordenada_x\";s:3:\"552\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1003,211,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:208:\"es el acopio de pedernales del [dios] Kiimil, [el dios] Jun Lajun Talaan es su anuncio. En otras palabras, si el dios A o de la muerte acopia pedernales el vaticinio es el dios Q de la guerra y el sacrificio.\";s:6:\"img_hp\";s:8:\"13_1.png\";s:10:\"texto_maya\";s:47:\"<i>moltok\' Kiimil, Jun Lajun Talaan umu\'uk.</i>\";s:12:\"coordenada_x\";s:3:\"143\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:101:\"es el acopio de cacao del [dios] Itzamna\' Kokaaj de las pepitas(?), [el pronóstico es] alimento (?).\";s:6:\"img_hp\";s:8:\"13_2.png\";s:10:\"texto_maya\";s:60:\"<i>mo[l]kaka[w] Itzamna[\'] Kokaaj saak[i]l(?), o\'och(?).</i>\";s:12:\"coordenada_x\";s:3:\"279\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:74:\"es el acopio de pájaros muy del búho de los Trece Cielos, es su anuncio.\";s:6:\"img_hp\";s:8:\"13_3.png\";s:10:\"texto_maya\";s:44:\"<i>mo[l]mu[y] Oxlajun Ka\'an kuy, umu\'uk.</i>\";s:12:\"coordenada_x\";s:3:\"413\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:147:\"es el acopio de tamales del [dios] Ik\'(?), mucha comida, ruin (?). Se trata de un pronóstico ambivalente, con un aspecto favorable y otro adverso.\";s:6:\"img_hp\";s:8:\"13_4.png\";s:10:\"texto_maya\";s:45:\"<i>mo[l]waaj Ik\'(?), ox wi\'[il], k\'as(?).</i>\";s:12:\"coordenada_x\";s:3:\"552\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1004,212,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:96:\"Itzamna\' Kokaaj de las pepitas(?) junta su cabeza en el señorío, [el augurio son] semillas(?).\";s:6:\"img_hp\";s:8:\"14_1.png\";s:10:\"texto_maya\";s:70:\"<i>nuch jol Itzamna[\'] Kokaaj saak[i]l(?) ti ajawle[l] hi\'inaj(?).</i>\";s:12:\"coordenada_x\";s:3:\"250\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:43:\"Kiimil [y] Trece Búhos juntan sus cabezas.\";s:6:\"img_hp\";s:8:\"14_2.png\";s:10:\"texto_maya\";s:34:\"<i>nuch jol Kiimil Oxlajun Kuy</i>\";s:12:\"coordenada_x\";s:3:\"552\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1005,213,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:92:\"Itzamna\' Kokaaj de las pepitas (?) pisó la casa, señorío es su crepúsculo vespertino(?).\";s:6:\"img_hp\";s:8:\"15_1.png\";s:10:\"texto_maya\";s:76:\"<i>utek\'aj naah Itzamna[\'] Kokaaj saak[i]l(?) ajawle[l] yook\'iin[i]l(?).</i>\";s:12:\"coordenada_x\";s:3:\"300\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:60:\"Jun Lajun Talaan pisó la casa, su anuncio es malo, ruin(?).\";s:6:\"img_hp\";s:8:\"15_2.png\";s:10:\"texto_maya\";s:62:\"<i>utek\'aj naah Jun Lajun Talaan, umu\'uk loba[l], k\'as(?).</i>\";s:12:\"coordenada_x\";s:3:\"505\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1006,214,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:92:\"Itzamna\' Kokaaj de las pepitas (?) junta la cabeza con Ahan(?), [el augurio es] alimento(?).\";s:6:\"img_hp\";s:8:\"16_1.png\";s:10:\"texto_maya\";s:65:\"<i>unuch jol Itzamna[\'] Kokaaj saak[i]l(?) Ahan(?), o\'och(?).</i>\";s:12:\"coordenada_x\";s:3:\"227\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:127:\"Kiimlal [y] Jun Lajun Talaan juntan sus cabezas. Es decir, el dios A de la muerte y el dios Q de la guerra se ponen de acuerdo.\";s:6:\"img_hp\";s:8:\"16_2.png\";s:10:\"texto_maya\";s:45:\"<i>unuch ujol Kiiml[a]l Jun Lajun Talaan.</i>\";s:12:\"coordenada_x\";s:3:\"511\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1007,215,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:69:\"es el alimento(?) de Itzamna\' Kokaaj de las pepitas, es su atardecer.\";s:6:\"img_hp\";s:8:\"17_1.png\";s:10:\"texto_maya\";s:55:\"<i>o\'och(?) Itzamna[\'] Kokaaj saak[i]l yook\'in[i]l.</i>\";s:12:\"coordenada_x\";s:3:\"313\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:53:\"es el alimento(?) de Kiimil, mortandad es su anuncio.\";s:6:\"img_hp\";s:8:\"17_2.png\";s:10:\"texto_maya\";s:40:\"<i>o\'och(?) Kiimil, cham[a]l umu\'uk.</i>\";s:12:\"coordenada_x\";s:3:\"483\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1008,216,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:60:\"[el augurio] entró en… Itzamná Kokaaj de las pepitas(?).\";s:10:\"texto_maya\";s:50:\"<i>[ochi tu… Itzamna\' Kokaaj] saak[i]l(?)…</i>\";s:6:\"img_hp\";s:8:\"18_1.png\";s:12:\"coordenada_x\";s:2:\"65\";s:12:\"coordenada_y\";s:2:\"14\";}i:1;a:5:{s:13:\"texto_espanol\";s:51:\"[el augurio entró en… del búho], es su anuncio.\";s:10:\"texto_maya\";s:27:\"<i>[ochi tu… u]mu\'uk.</i>\";s:6:\"img_hp\";s:8:\"18_2.png\";s:12:\"coordenada_x\";s:3:\"217\";s:12:\"coordenada_y\";s:2:\"13\";}i:2;a:5:{s:13:\"texto_espanol\";s:94:\"[el augurio] entró en el pensamiento de Wak Ik\'(?), [el pornóstico es] tutaal, mucha comida.\";s:10:\"texto_maya\";s:53:\"<i>ochi [tuk]ba[l] Wak Ik\'(?) tutaal, ox wi\'[il].</i>\";s:6:\"img_hp\";s:8:\"18_3.png\";s:12:\"coordenada_x\";s:3:\"351\";s:12:\"coordenada_y\";s:2:\"13\";}i:3;a:5:{s:13:\"texto_espanol\";s:69:\"[el augurio] entró en la palabra de Kiimil, mortandad es su anuncio.\";s:10:\"texto_maya\";s:46:\"<i>och[i] tuchich Kiimil, cham[a]l umu\'uk.</i>\";s:6:\"img_hp\";s:8:\"18_4.png\";s:12:\"coordenada_x\";s:3:\"475\";s:12:\"coordenada_y\";s:2:\"13\";}i:4;a:5:{s:13:\"texto_espanol\";s:94:\"[el augurio] entró en el pensamiento de Ahan(?), [el pronóstico es] alimento(?), pepitas(?).\";s:10:\"texto_maya\";s:54:\"<i>och[i] tukba[l] Ahan(?), o\'och(?), saak[i]l(?).</i>\";s:6:\"img_hp\";s:8:\"18_5.png\";s:12:\"coordenada_x\";s:3:\"646\";s:12:\"coordenada_y\";s:2:\"14\";}}'),
	(1009,217,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:66:\"el cacao de Chaak ya había entrado, [el augurio es] mucha comida.\";s:10:\"texto_maya\";s:39:\"<i>ochiiy ukakaw Chaak, ox wi\'[il].</i>\";s:6:\"img_hp\";s:8:\"19_1.png\";s:12:\"coordenada_x\";s:3:\"303\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:71:\"el cacao de Jun Lajun Talaan ya había entrado, [el augurio es] maldad.\";s:10:\"texto_maya\";s:45:\"<i>ochiiy ukakaw Jun Lajun Talaan, lobal.</i>\";s:6:\"img_hp\";s:8:\"19_2.png\";s:12:\"coordenada_x\";s:3:\"435\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(1010,218,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:133:\"K\'awiil se hizo redondo, [el augurio es] mucha comida, señores puestos en orden. Es decir, víveres y buen curso de los gobernantes.\";s:10:\"texto_maya\";s:45:\"<i>petaj K\'awiil, ox wi\'[il], tz\'ak ajaw.</i>\";s:6:\"img_hp\";s:8:\"20_1.png\";s:12:\"coordenada_x\";s:3:\"153\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:51:\"K\'in Ajaw se hizo redondo, castigo por fuego, malo.\";s:10:\"texto_maya\";s:47:\"<i>petaj K\'in Ajaw, k\'ahk\' te\' tuun, lobal.</i>\";s:6:\"img_hp\";s:8:\"20_2.png\";s:12:\"coordenada_x\";s:3:\"262\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:55:\"Ahan(?) se hizo redondo, [hay] comida(\') en su palabra.\";s:10:\"texto_maya\";s:39:\"<i>petaj Ahan(?), o\'och(?) tuchich.</i>\";s:6:\"img_hp\";s:8:\"20_3.png\";s:12:\"coordenada_x\";s:3:\"428\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:71:\"[el augurio] se hizo redondo en la palabra del zopilote, es su anuncio.\";s:10:\"texto_maya\";s:36:\"<i>petaj tuchich k\'uuch, umu\'uk.</i>\";s:6:\"img_hp\";s:8:\"20_4.png\";s:12:\"coordenada_x\";s:3:\"567\";s:12:\"coordenada_y\";s:1:\"1\";}i:4;a:5:{s:13:\"texto_espanol\";s:93:\"[el augurio] se hizo redondo en la palabra del mono araña, [el pronóstico es] mucha comida.\";s:10:\"texto_maya\";s:38:\"<i>petaj tuchich maax, ox wi\'[il].</i>\";s:6:\"img_hp\";s:8:\"20_5.png\";s:12:\"coordenada_x\";s:3:\"633\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
