	(1126,233,'id_seccion',''),
	(1127,233,'id_notas','<p>Una nueva columna de signos de los días, cuyo coeficiente numérico rojo está borado, sugiere que se trata de otro almanaque.</p>'),
	(1128,233,'id_tematica','Almanaques de la diosa lunar'),
