	(1329,245,'id_notas',''),
	(1330,245,'id_tematica',''),
	(1331,245,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:484:\"Imagen de la anciana diosa O o Chak Chel (izquierda) y del dios H o Ik’(?), numen del viento y de las  flores, sosteniendo agujas y flanqueando un bastidor. El logograma del dios H es una variante tardía del antiguo jeroglífico para Ik’, ‘viento’, que según Taube (1992) en el periodo Clásico suele tener una flor en el tocado y que, a su vez, como argumentaba Thompson (1950), podía operar como variante personificada del número 3 (ver también Nájera Coronado, 2015).\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
