	(1368,246,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:144:\"El dios del maíz Ahan(?) se encuentra sujetando la aguja, el hilo y el bastidor (izquierda), mientras que el dios D o Itzamna’ hace lo mismo.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
