	(1633,267,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:258:\"Dios H o Ik\' (?) dios del viento y de las flores sobre un campo verde o azul maya; está sentado en flor de loto y presenta cierto escorzo en la pierna izquierda; con la mano derecha ase un objeto que parece incluir una caracola, un tallo y una hoja vegetal.\";s:6:\"img_hp\";s:0:\"\";}}'),
