	(1707,277,'id_notas',' <p>El almanaque no muestra en esta sección viñeta iconográfica, solamente el augurio. Wuk Si\'ip es una deidad asociada con los ámbitos indómitos del bosque.</p>'),
	(1708,277,'id_tematica','Almanaques de la diosa lunar'),
	(1709,277,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:53:\"Ixik Uh es la esposa de Wuk Si\'ip, [augurio] ruin(?).\";s:6:\"img_hp\";s:8:\"45_1.png\";s:10:\"texto_maya\";s:42:\"<i>yat[a]n Ixik Uh Wuk Si\'ip, k\'as(?)</i>.\";s:12:\"coordenada_x\";s:3:\"278\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:63:\"Ixik Uh es el pago de Sak Ik\'(?), [el augurio son] pepitas (?).\";s:6:\"img_hp\";s:8:\"45_2.png\";s:10:\"texto_maya\";s:48:\"<i>yat[aa]l Ixik Uh Sak Ik\'(?), saak[i]l(?)</i>.\";s:12:\"coordenada_x\";s:3:\"423\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
