	(1907,286,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:300:\"Dios H de las flores y del viento, Ik’(?), quien usa un gorro o mitra sacerdotal y lleva un punzón empleado para el autosacrificio, sujetado entre su banda o diadema. El objeto que sostiene con la mano izquierda es poco claro, pero podemos intuir que se trata de tamales o tortillas (<i>waaj</i>).\";s:6:\"img_hp\";s:0:\"\";}}'),
	(1908,317,'_post_template','Seccion_Hotspot_A.php'),
	(1909,317,'id_correo',NULL),
	(1910,317,'id_usuario',NULL),
	(1911,317,'id_IDhotspots',NULL),
