	(1931,287,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:456:\"Dios A o Kiimil, dios de la muerte sobre fondo rojo; emite de su boca el último hálito; está descarnado, aunque aún tiene tiras de tejido blando en la columna vertebral; y en su esfínter lleva el signo silábico <b>mo</b>, que forma parte de la palabra <i>mool</i>, ‘recto, ano’, tal vez en alusión a la degradación anaeróbica por bacterias que produce flatulencias en los cadáveres. Lleva globos oculares humanos en la collera y las muñecas.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
