	(2161,306,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:244:\"El dios A de la muerte ocupa la primera y la tercer viñeta, mientras que en medio encontramos al dios H del viento y de las flores, todos realizando ademanes con la mano derecha de significado desconocido, que sugieren algún tipo de diálogo.\";s:6:\"img_hp\";s:0:\"\";}}'),
