	(2209,310,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:310:\"Chaak y el dios de la muerte Kiimil protagonizan este almanaque. Ambos sostienen escudillas llenas de vainas de cacao. Chaak, dios de la lluvia, tiene un tocado de ninfea. Kiimil luce manchas de putrefacción en el cuerpo, globos oculares humanos en la collera, un tocado de saurio enfatiza su ano o esfínter.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
