	(2472,323,'id_notas',''),
	(2473,323,'id_tematica',''),
	(2474,323,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:210:\"Las viñetas están ocupadas por las imágenes del dios Kiimil o de la muerte y de Itzamna’ o dios D. Ambos sostienen una flor (<i>nikte’</i>, ‘plumería’ [<i>vid</i>. Davoust, 139]) en la mano derecha.\";s:6:\"img_hp\";s:0:\"\";}}'),
	(2475,324,'_post_template','Seccion_Hotspot_B.php'),
