	(2534,331,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:188:\"Ambas viñetas representan a la diosa I o Ixik Uh. La que está de pie carga al dios de la lluvia Chaak sobre la espalda.  La que está sentada carga al dios de la muerte sobre la espalda.\";s:6:\"img_hp\";s:0:\"\";}}'),
