	(2618,338,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:197:\"La diosa lunar joven o Ixik Uh \'Señora de la Luna \' aunque los textos jeroglíficos acompañantes están casi perdidos. La diosa sostiene el posible jeroglífico <i>i’inaj</i>(?), ‘semilla’.\";s:6:\"img_hp\";s:0:\"\";}}'),
