	(2629,339,'id_tematica',''),
	(2630,339,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:271:\"La diosa lunar joven o Ixik Uh \'Señora de la Luna \', sostiene sobre la mano los jeroglíficos ya’ax, ‘verde’, y <i>k’an</i>, ‘amarillo’, que conforman un <i>difrasismo</i> habitual en las literaturas maya y náhuatl, equivalente a gloria, riqueza o majestad.\";s:6:\"img_hp\";s:0:\"\";}}'),
