	(2654,341,'id_tematica',''),
	(2655,341,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:309:\"Sobre la diosa  lunar joven Ixik Uh \'Señora de la Luna \', aparece la cadavérica imagen del dios de la muerte (Kiimil). En el centro se encuentra la diosa, portando el jeroglífico del color blanco. A su derecha observamos otra vez que el ave <i>muwaan</i> o búho (<i>kuy</i>) se posa sobre la misma deidad.\";s:6:\"img_hp\";s:0:\"\";}}'),
	(2656,342,'_post_template','Seccion_Hotspot_A.php'),
