	(2704,345,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:235:\"La diosa  I o lxik Uh, \'Señora de la Luna\', portando un gorro que Thompson (1972) cree que es de papel; en la nariz parece llevar una flor. A su derecha la misma deidad frente a una aura (<i>k’uuch o ta’ jol</i>) antropomorfizada.\";s:6:\"img_hp\";s:0:\"\";}}'),
