	(2728,347,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:175:\"Menos afectuosa luce la diosa  I, lxik Uh, \'Señora de la Luna\' o Sak Ixik, \'Mujer Blanca\', delante del señor de la muerte. Ella cierra los ojos en alusión al fallecimiento.\";s:6:\"img_hp\";s:0:\"\";}}'),
