	(2836,356,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:337:\"A la izquierda la diosa  I o lxik Uh, \'Señora de la Luna\', interactúa con el anciano dios D o Itzamna’, mismo que aparece casi sentado sobre sus piernas. A la derecha, la podemos observar en posición sedente, con el cabello negro, una banda o diadema de dos hileras de cuentas y la mano derecha extendida con el pulgar hacia arriba.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
