	(3201,381,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:137:\"En la imagen tenemos al extranjero flechado que menciona el texto de arriba. Se encuentra derribado sobre el piso y derrama una lágrima.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
