	(3423,400,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:83:\"la Gran Estrella Itzam Ayiin … elotes(?)…, sepulcros dolorosos, niños heridos.\";s:6:\"img_hp\";s:9:\"56_1d.png\";s:10:\"texto_maya\";s:76:\"<i>[… Itzam Ayiin Chak Ek\'…] ahan(?), yaj ch\'e\'enal… yaj ch\'ok…</i>.\";s:12:\"coordenada_x\";s:3:\"393\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
