	(3437,401,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:192:\"la Gran Estrella Ha\'al Ik\' Mam se manifestó en el este; [el dios] K\'awiil es su [víctima] flechada, Luna dolorosa, hombres heridos, su anuncio es riqueza, elotes(?) dañados, comida enferma.\";s:10:\"texto_maya\";s:126:\"<i>k\'al[a]j lak\'in Ha\'al Ik\' Mam Chak Ek\'; K\'awiil ujul, yaj Uh, yaj winik, umu\'uk uya\'ax uk\'an, yaj ahan(?), yaj wi\'[il]</i>.\";s:6:\"img_hp\";s:9:\"57_1d.png\";s:12:\"coordenada_x\";s:3:\"448\";s:12:\"coordenada_y\";s:1:\"7\";}i:1;a:5:{s:13:\"texto_espanol\";s:64:\"[En] <4 yaxkin> la gran estrella pavo se manifestó en el norte.\";s:10:\"texto_maya\";s:45:\"<i>4 yahxk\'in k\'al[aj] nal ulum Chak Ek\'</i>.\";s:6:\"img_hp\";s:8:\"57_2.png\";s:12:\"coordenada_x\";s:3:\"247\";s:12:\"coordenada_y\";s:2:\"59\";}i:2;a:5:{s:13:\"texto_espanol\";s:67:\"En] <14 zac> la gran estrella escorpión se manifestó en el oeste.\";s:10:\"texto_maya\";s:44:\"<i>14 saksijo\'m k\'al[aj] sinan Chak Ek\'</i>.\";s:6:\"img_hp\";s:8:\"57_3.png\";s:12:\"coordenada_x\";s:3:\"299\";s:12:\"coordenada_y\";s:2:\"59\";}i:3;a:5:{s:13:\"texto_espanol\";s:70:\"[En] <19 tzeec> la gran estrella perro grande se manifestó en el sur.\";s:10:\"texto_maya\";s:52:\"<i>19 tze\'k k\'al[aj] noh[ol] chak pek\' Chak Ek\'</i>.\";s:6:\"img_hp\";s:8:\"57_4.png\";s:12:\"coordenada_x\";s:3:\"351\";s:12:\"coordenada_y\";s:2:\"59\";}i:4;a:5:{s:13:\"texto_espanol\";s:61:\"[En] <7 xul>la gran estrella Kiimil se manifestó en el este.\";s:10:\"texto_maya\";s:52:\"<i>7 chi\'ik[i]n k\'al[aj] lak\'in Kiimil Chak Ek\'</i>.\";s:6:\"img_hp\";s:8:\"57_5.png\";s:12:\"coordenada_x\";s:3:\"403\";s:12:\"coordenada_y\";s:2:\"59\";}}'),
