	(3557,406,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:240:\"Observamos al dios B o de la lluvia Chaak en actitud de caminar bajo la lluvia; con la mano izquierda porta el hacha-relámpago, mientras que con la derecha, en segundo plano después de la rodela, sostiene una serpiente virada hacia abajo.\";s:6:\"img_hp\";s:0:\"\";}}'),
