	(3640,413,'id_tematica',''),
	(3641,413,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:298:\"La escena muestra a Chaak desplazándose en aparente actitud marcial, pues en la mano derecha porta una lanza y en la izquierda una rodela acompañada por una serpiente con las fauces abiertas; en el centro del escudo apreciamos el jeroglífico de <i>hiix</i>, término ritual para el ‘jaguar’.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
