	(3861,445,'repeatable_fields_2','a:5:{i:0;a:5:{s:13:\"texto_espanol\";s:170:\"la Gran Estrella Kan Itzamtuun…, [el augurio es] señorío, mucha comida, pepitas(?), llegada de pulque blanco … disentería en el año, es el anuncio de los hombres.\";s:10:\"texto_maya\";s:131:\"<i>[… Kan Itzamtuun Chak Ek…] ajawle[l], ox wi\'[il], saak[i]l(?) sak hulki[\'] … yo… puchil ti haab[i]l, umu\'uk wi[nik]</i>.\";s:6:\"img_hp\";s:9:\"62_1d.png\";s:12:\"coordenada_x\";s:3:\"156\";s:12:\"coordenada_y\";s:1:\"4\";}i:1;a:5:{s:13:\"texto_espanol\";s:68:\"[En] <17 yaax> la Gran Estrella K\'in Ajaw se manifestó en el norte.\";s:10:\"texto_maya\";s:53:\"<i>17 ya\'xsijo\'m k\'al[a]j nal K\'in Ajaw Chak Ek\'</i>.\";s:6:\"img_hp\";s:9:\"62_10.png\";s:12:\"coordenada_x\";s:2:\"12\";s:12:\"coordenada_y\";s:3:\"319\";}i:2;a:5:{s:13:\"texto_espanol\";s:66:\"<7 muan> la Gran Estrella Wak Yich Ajaw se manifestó en el oeste.\";s:10:\"texto_maya\";s:58:\"<i>7 muwaan k\'al[a]j chik\'in Wak Yich [Ajaw] Chak Ek\'</i>.\";s:6:\"img_hp\";s:9:\"62_11.png\";s:12:\"coordenada_x\";s:2:\"52\";s:12:\"coordenada_y\";s:3:\"319\";}i:3;a:5:{s:13:\"texto_espanol\";s:74:\"[En] <12 cħeen> la Gran Estrella … Ahk\'ab Ajaw se manifestó en el sur.\";s:10:\"texto_maya\";s:62:\"<i>12 ik\'sijo\'m k\'al[a]j noh[ol] … Ahk\'ab Ajaw Chak Ek\'</i>.\";s:6:\"img_hp\";s:9:\"62_12.png\";s:12:\"coordenada_x\";s:2:\"86\";s:12:\"coordenada_y\";s:3:\"319\";}i:4;a:5:{s:13:\"texto_espanol\";s:64:\"[En] <0 yaax> la Gran Estrella Uh Ajaw se manifestó en el este.\";s:10:\"texto_maya\";s:59:\"<i>13 chum ya\'xsijo\'m k\'al[a]j lak\'in Uh Ajaw Chak Ek\'</i>.\";s:6:\"img_hp\";s:9:\"62_13.png\";s:12:\"coordenada_x\";s:3:\"120\";s:12:\"coordenada_y\";s:3:\"319\";}}');
