	(3887,447,'id_notas',' <p>Un lugar sacro semejante al <i>K\'ante\'nal</i> se menciona varios siglos antes en la Estela 31 de Tikal: <i>K\'ante\'na[\']</i>, mientras que <i>Wuk Ha\'nal</i>, ‘Lugar de Siete Aguas’, es sin duda el nombre de otra locación sagrada.</p>      '),
	(3888,447,'id_tematica','Tabla del planeta Venus'),
	(3889,447,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:116:\"durante tres lunas, tres veintenas, es el anuncio del señor de K\'ante\'nal, es el anuncio del oriente en Wuk Ha\'nal.\";s:6:\"img_hp\";s:9:\"64_1d.png\";s:10:\"texto_maya\";s:101:\"<i>ox ti uh, ox tuwinal umu\'uk K\'ante\'nal ajaw, umu\'uk K\'ante\'nal ajaw, umu\'uk lak\'in Wuk Ha\'nal</i>.\";s:12:\"coordenada_x\";s:3:\"248\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
