	(4729,510,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:230:\"En la escena apreciamos a Chaak sentado serenamente sobre un cuerpo de agua, mismo que se encuentra envuelto por los troncos de un árbol, que seguramente es de <i>tz’ite’</i> o pito. Éste contiene un amplio espacio interior.\";s:6:\"img_hp\";s:0:\"\";}}'),
