	(5036,544,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:268:\"Se aprecia a Chaak caminado con una antorcha de sequía y con una rodela flamígera, que recuerda el nombre de un antiguo capitán (Kelley, 1962; 1968) y dios maya de la guerra (López Cogolludo, 1688): K’ahk’ Upakal o &ltKakupacal&gt, ‘el Fuego es su Escudo’.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
