	(5171,555,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:230:\"En la escena Chaak aparece sentado sobre el agua, mientras sujeta una culebra acuática. Una deidad sumergida hunde sus pies dentro de un gran caracol. Thompson (1972) la identificó como un <i>Ba’ Kaab</i> o <i>&ltBacab&gt</i>.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
