	(5750,599,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:201:\"Thompson (1972) describió la escena de forma inmejorable: Chaak adopta una postura acurrucada, mira hacia arriba, sostiene un objeto semejante a una antorcha y entre sus piernas hay una rama o árbol.\";s:6:\"img_hp\";s:0:\"\";}}'),
