	(5936,614,'repeatable_fields_2','a:1:{i:0;a:2:{s:13:\"texto_espanol\";s:305:\"La frase que se puede leer arriba de las tres escenas de esta lámina, ‘Aak(?) fue cortado con golpe de hacha’, puede estar relacionada con las viñetas figurativas de estos <i>t’o’ol</i>, donde el pintor maya sólo representó la mitad del cuerpo de Aak(?) descendiendo de una rajada en el cielo.\";s:6:\"img_hp\";s:0:\"\";}}'),
