	(6375,658,'repeatable_fields_2','a:6:{i:0;a:5:{s:13:\"texto_espanol\";s:50:\"Chaak está en el agua, [el augurio son] pescados.\";s:10:\"texto_maya\";s:36:\"<i>ayan[a]w ta ha’ Chaak, kay</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:2:\"51\";s:12:\"coordenada_y\";s:2:\"21\";}i:1;a:5:{s:13:\"texto_espanol\";s:63:\"Chaak está en la ciudad, [el augurio es] Kan Pek’ Winkil(?).\";s:10:\"texto_maya\";s:62:\"<i>ayan[a]w kab ch’e’en Chaak, Kan Pe[k’] Winkil(?)</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:3:\"170\";s:12:\"coordenada_y\";s:2:\"21\";}i:2;a:5:{s:13:\"texto_espanol\";s:66:\"Chaak está en el cielo, [el augurio son] tamales(?) de iguana(?).\";s:10:\"texto_maya\";s:49:\"<i>ayan[a]w ti ka’an Chaak, huh(?) waaj(?)</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:3:\"280\";s:12:\"coordenada_y\";s:2:\"21\";}i:3;a:5:{s:13:\"texto_espanol\";s:63:\"Chaak está en el camino, [el pronóstico son] tamales de pavo.\";s:10:\"texto_maya\";s:40:\"<i>ayan[a]w ta bih Chaak, kutz waaj</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:3:\"417\";s:12:\"coordenada_y\";s:2:\"21\";}i:4;a:5:{s:13:\"texto_espanol\";s:69:\"Chaak está en su casa, [el augurio son] tamales y tortillas grandes.\";s:10:\"texto_maya\";s:45:\"<i>ayan[a]w yotoch Chaak, chak waaj waaj</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:3:\"548\";s:12:\"coordenada_y\";s:2:\"21\";}i:5;a:5:{s:13:\"texto_espanol\";s:86:\"Chaak está trayendo muchas [hachas] en las manos, [el augurio son] piernas de venado.\";s:10:\"texto_maya\";s:47:\"<i>ayan[a]w bolon pe[’] Chaak, yook chij</i>.\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:3:\"678\";s:12:\"coordenada_y\";s:2:\"21\";}}'),
