	(6909,716,'id_posicion','0.10679999999999994'),
	(6910,716,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:236:\"Figura que representa un felino manchado, con una flor sobre la cabeza, posiblemente ninfea. El texto jeroglífico lo llama <i>Chak Bolay</i>, ‘Gran Depredador’ o ‘Gran Tigrillo’, o simplemente ‘Depredador’ o ‘Tigrillo’.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
