	(7287,858,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:207:\"En esta imagen una lluvia torrencial cae sobre K’uh, personificación de la sacralidad por excelencia. K’uh sostiene un tamal o tortilla sobre la mano derecha en señal de que su pronóstico es alimento.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
