	(7559,220,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:49:\"el cacao de K\'awiil Ahan(?) entró, mucha comida.\";s:10:\"texto_maya\";s:48:\"<i>och[i] kakaw K\'awiil Ahan(?), ox wi\'[il].</i>\";s:6:\"img_hp\";s:8:\"22_1.png\";s:12:\"coordenada_x\";s:3:\"321\";s:12:\"coordenada_y\";s:2:\"17\";}i:1;a:5:{s:13:\"texto_espanol\";s:39:\"… Oxlajun Ka\'an Winkil(?), mortandad.\";s:10:\"texto_maya\";s:45:\"<i>… Oxlajun Ka\'an Winkil(?), cham[a]l.</i>\";s:6:\"img_hp\";s:8:\"22_2.png\";s:12:\"coordenada_x\";s:3:\"476\";s:12:\"coordenada_y\";s:2:\"17\";}}'),
	(7560,219,'repeatable_fields_2','a:6:{i:0;a:5:{s:13:\"texto_espanol\";s:60:\"[el dios] Kiimlal recoge, [el augurio es] mortandad, maldad.\";s:6:\"img_hp\";s:8:\"21_1.png\";s:10:\"texto_maya\";s:39:\"<i>[u]mol Kiiml[a]l cham[a]l lobah.</i>\";s:12:\"coordenada_x\";s:2:\"90\";s:12:\"coordenada_y\";s:2:\"17\";}i:1;a:5:{s:13:\"texto_espanol\";s:94:\"[el dios] Itzamna\' Kokaaj de las pepitas(?) recoge, [el augurio es] señores puestos en orden.\";s:6:\"img_hp\";s:8:\"21_2.png\";s:10:\"texto_maya\";s:51:\"<i>umol Itzamna[\'] Kokaaj saak[i]l, tz\'ak ajaw.</i>\";s:12:\"coordenada_x\";s:3:\"197\";s:12:\"coordenada_y\";s:2:\"17\";}i:2;a:5:{s:13:\"texto_espanol\";s:56:\"[el dios] Jun Lajun Talaan recoge, su anuncio es maldad.\";s:6:\"img_hp\";s:8:\"21_3.png\";s:10:\"texto_maya\";s:43:\"<i>umol Jun Lajun Talaan, umu\'uk lobal.</i>\";s:12:\"coordenada_x\";s:3:\"291\";s:12:\"coordenada_y\";s:2:\"17\";}i:3;a:5:{s:13:\"texto_espanol\";s:68:\"[el dios] Ahan(?) recoge, [el augurio es] alimento(?), mucha comida.\";s:6:\"img_hp\";s:8:\"21_4.png\";s:10:\"texto_maya\";s:42:\"<i>umol Ahan(?), o\'och(?), ox wi\'[il].</i>\";s:12:\"coordenada_x\";s:3:\"409\";s:12:\"coordenada_y\";s:2:\"17\";}i:4;a:5:{s:13:\"texto_espanol\";s:60:\"[el dios] K\'in Ajaw recoge, castigo por fuego es su anuncio.\";s:6:\"img_hp\";s:8:\"21_5.png\";s:10:\"texto_maya\";s:46:\"<i>umol Kín Ajaw, k\'ahk\' te\' tuun umu\'uk.</i>\";s:12:\"coordenada_x\";s:3:\"542\";s:12:\"coordenada_y\";s:2:\"17\";}i:5;a:5:{s:13:\"texto_espanol\";s:58:\"[el dios] Chaak recoge, tronos(?) de señores, bendición.\";s:6:\"img_hp\";s:8:\"21_6.png\";s:10:\"texto_maya\";s:41:\"<i>umol Chaak, tz\'am(?) ajaw, yutzil.</i>\";s:12:\"coordenada_x\";s:3:\"665\";s:12:\"coordenada_y\";s:2:\"17\";}}'),
	(7561,221,'repeatable_fields_2','a:3:{i:0;a:5:{s:13:\"texto_espanol\";s:60:\"[el dios] Kiimlal se hizo redondo, gemidos(?) son su anuncio\";s:6:\"img_hp\";s:8:\"23_1.png\";s:10:\"texto_maya\";s:38:\"<i>petaj Kiiml[a]l ahkan(?) umu\'uk</i>\";s:12:\"coordenada_x\";s:3:\"235\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:73:\"[el dios] Ik\'(?) se hizo redondo, [el augurio es] alimento(?), pepitas(?)\";s:6:\"img_hp\";s:8:\"23_2.png\";s:10:\"texto_maya\";s:40:\"<i>petaj Ik\'(?) o\'och(?) saak[i]l(?)</i>\";s:12:\"coordenada_x\";s:3:\"382\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:57:\"[el dios] Kiimil se hizo redondo, mortandad es su anuncio\";s:6:\"img_hp\";s:8:\"23_3.png\";s:10:\"texto_maya\";s:36:\"<i>petaj Kiimil, cham[a]l umu\'uk</i>\";s:12:\"coordenada_x\";s:3:\"503\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7562,222,'repeatable_fields_2','a:3:{i:0;a:5:{s:13:\"texto_espanol\";s:65:\"[el dios] Ik\'(?) reconoce [la] flor, [el augurio son] pepitas(?).\";s:6:\"img_hp\";s:8:\"24_1.png\";s:10:\"texto_maya\";s:40:\"<i>k\'a[ha]w nikte\' Ik\'(?), saak[i]l</i>.\";s:12:\"coordenada_x\";s:3:\"235\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:69:\"[el dios] Ho\' Tuun Itzam reconoce [la] flor, [el augurio son] elotes.\";s:6:\"img_hp\";s:8:\"24_2.png\";s:10:\"texto_maya\";s:46:\"<i>k\'a[ha]w nikte\' Ho\' Tuun Itzam ahan(?)</i>.\";s:12:\"coordenada_x\";s:3:\"367\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:58:\"[el dios] K\'in Ajaw reconoce [la] flor, castigo por fuego.\";s:6:\"img_hp\";s:8:\"24_3.png\";s:10:\"texto_maya\";s:50:\"<i>k\'a[ha]w nikte\' K\'in Ajaw, k\'ahk\' te\' tuun</i>.\";s:12:\"coordenada_x\";s:3:\"488\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7563,223,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:72:\"el cacao de [Chaak] entró, [los augurios son] señorío [y] pepitas(?).\";s:6:\"img_hp\";s:8:\"25_1.png\";s:10:\"texto_maya\";s:47:\"<i>[ochi ka]kaw…, ajawle[l], saak[i]l(?)</i>.\";s:12:\"coordenada_x\";s:3:\"239\";s:12:\"coordenada_y\";s:2:\"25\";}i:1;a:5:{s:13:\"texto_espanol\";s:61:\"el cacao de Kiimil entró, [el augurio es] maldad, mortandad.\";s:6:\"img_hp\";s:8:\"25_2.png\";s:10:\"texto_maya\";s:44:\"<i>och[i] kakaw Kiimil, lobal, cham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"424\";s:12:\"coordenada_y\";s:2:\"25\";}}'),
	(7564,209,'repeatable_fields_2','a:6:{i:0;a:5:{s:13:\"texto_espanol\";s:57:\"[el dios] Kiimil come tamales, [el augurio] es mortandad.\";s:10:\"texto_maya\";s:35:\"<i>umak\' waaj Kiimil, cham[a]l</i>.\";s:6:\"img_hp\";s:8:\"26_1.png\";s:12:\"coordenada_x\";s:2:\"51\";s:12:\"coordenada_y\";s:2:\"20\";}i:1;a:5:{s:13:\"texto_espanol\";s:75:\"[el dios] Ahan(?) come tamales, [el augurios es] señores puestos en orden.\";s:10:\"texto_maya\";s:38:\"<i>umak\' waaj Ahan(?), tz\'ak ajaw</i>.\";s:6:\"img_hp\";s:8:\"26_2.png\";s:12:\"coordenada_x\";s:3:\"164\";s:12:\"coordenada_y\";s:2:\"20\";}i:2;a:5:{s:13:\"texto_espanol\";s:48:\"K\'uh come tamales, [el augurio] es mucha comida.\";s:10:\"texto_maya\";s:35:\"<i>umak\' waaj K\'uh, ox wi\'[il]</i>.\";s:6:\"img_hp\";s:8:\"26_3.png\";s:12:\"coordenada_x\";s:3:\"285\";s:12:\"coordenada_y\";s:2:\"20\";}i:3;a:5:{s:13:\"texto_espanol\";s:55:\"Ha\'al Ik\' Mam come tamales, [el augurio es] bendición.\";s:10:\"texto_maya\";s:46:\"<i> mak\'aw waaj[a]j Ha\'al Ik\' Mam, yutzil</i>.\";s:6:\"img_hp\";s:8:\"26_4.png\";s:12:\"coordenada_x\";s:3:\"425\";s:12:\"coordenada_y\";s:2:\"20\";}i:4;a:5:{s:13:\"texto_espanol\";s:46:\"Jun Lajun Talaan come tamales, es su  anuncio.\";s:10:\"texto_maya\";s:48:\"<i>mak\'aw waaj[a]j Jun Lajun Talaan, umu\'uk</i>.\";s:6:\"img_hp\";s:8:\"26_5.png\";s:12:\"coordenada_x\";s:3:\"550\";s:12:\"coordenada_y\";s:2:\"20\";}i:5;a:5:{s:13:\"texto_espanol\";s:58:\"Itzamna\' Kokaaj come tamales, [el augurio son] pepitas(?).\";s:10:\"texto_maya\";s:53:\"<i>mak\'aw waaj[a]j Itzamna[\'] Kokaaj saak[i]l(?)</i>.\";s:6:\"img_hp\";s:8:\"26_6.png\";s:12:\"coordenada_x\";s:3:\"669\";s:12:\"coordenada_y\";s:2:\"20\";}}'),
	(7565,227,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:58:\"Kan Chij Winkil(?) es el pago de Wuk Si\'ip, es su anuncio.\";s:10:\"texto_maya\";s:53:\"<i>Kan Chi[j] Winkil(?) yataal Wuk Si\'ip, umu\'uk</i>.\";s:6:\"img_hp\";s:8:\"27_1.png\";s:12:\"coordenada_x\";s:2:\"94\";s:12:\"coordenada_y\";s:2:\"20\";}i:1;a:5:{s:13:\"texto_espanol\";s:55:\"el zopilote es el pago del perro, [el augurio es] ruin.\";s:10:\"texto_maya\";s:35:\"<i>k\'uuch yataal tzul, k\'as(?)</i>.\";s:6:\"img_hp\";s:8:\"27_2.png\";s:12:\"coordenada_x\";s:3:\"252\";s:12:\"coordenada_y\";s:2:\"20\";}i:2;a:5:{s:13:\"texto_espanol\";s:116:\"<i>taliim</i> es el pago de Itzamna\' Kokaaj, [los augurios son] hijos de madre y de padre, pepitas(?), mucha comida.\";s:10:\"texto_maya\";s:78:\"<i>taliim yat[aa]l Itzamna[\'] Kokaaj, al [u]ne[n] saak[i] l(?) ox wi\'[il]</i>.\";s:6:\"img_hp\";s:8:\"27_3.png\";s:12:\"coordenada_x\";s:3:\"427\";s:12:\"coordenada_y\";s:2:\"20\";}i:3;a:5:{s:13:\"texto_espanol\";s:106:\"Sak Ixik es la esposa de Ha\'al Ik\' Mam, [los augurios son] bendición, tronos(?) de señores, alimento(?).\";s:10:\"texto_maya\";s:69:\"<i>Sak Ixik yatan Ha\'al Ik\' Mam, yutzil, tz\'am(?) ajaw, o\'och(?)</i>.\";s:6:\"img_hp\";s:8:\"27_4.png\";s:12:\"coordenada_x\";s:3:\"611\";s:12:\"coordenada_y\";s:2:\"20\";}}'),
	(7566,228,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:59:\"es el ave predadora del sur, Ahan(?) la trajo en las manos.\";s:10:\"texto_maya\";s:39:\"<i>nohol utz\'ikiin, upe[\'] Ahan(?)</i>.\";s:6:\"img_hp\";s:8:\"28_1.png\";s:12:\"coordenada_x\";s:3:\"199\";s:12:\"coordenada_y\";s:2:\"20\";}i:1;a:5:{s:13:\"texto_espanol\";s:60:\"es el ave predadora del norte, Ik\'(?) la trajo en las manos.\";s:10:\"texto_maya\";s:38:\"<i>nal [utz\'ikiin], upe[\'] Ik\'(?)</i>.\";s:6:\"img_hp\";s:8:\"28_2.png\";s:12:\"coordenada_x\";s:3:\"317\";s:12:\"coordenada_y\";s:2:\"20\";}i:2;a:5:{s:13:\"texto_espanol\";s:71:\"es el ave predadora del [rumbo cardinal], Kiimil la trajo en las manos.\";s:10:\"texto_maya\";s:37:\"<i>[… utz\'ikiin] upe[\'] Kiimil</i>.\";s:6:\"img_hp\";s:8:\"28_3.png\";s:12:\"coordenada_x\";s:3:\"420\";s:12:\"coordenada_y\";s:2:\"20\";}i:3;a:5:{s:13:\"texto_espanol\";s:74:\"es el ave predadora del [rumbo cardinal], la trajo en las manos K\'in Ajaw.\";s:10:\"texto_maya\";s:40:\"<i>[… utz\'ikiin K\'in Ajaw] upe[\']</i>.\";s:6:\"img_hp\";s:8:\"28_4.png\";s:12:\"coordenada_x\";s:3:\"546\";s:12:\"coordenada_y\";s:2:\"20\";}}'),
	(7567,229,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:60:\"Itzamna\' Kokaaj plantó el alimento, [el augurio es] tabaco.\";s:10:\"texto_maya\";s:50:\"<i>[upa]k\'aj tzeen Itzamna[\'] Kokaaj, k\'uuhtz</i>.\";s:6:\"img_hp\";s:8:\"29_1.png\";s:12:\"coordenada_x\";s:3:\"282\";s:12:\"coordenada_y\";s:2:\"16\";}i:1;a:5:{s:13:\"texto_espanol\";s:37:\"Kiiml[a]l plantó el alimento tabaco.\";s:10:\"texto_maya\";s:41:\"<i>upak\'a[j] k\'uuhtz tzeen Kiiml[a]l</i>.\";s:6:\"img_hp\";s:8:\"29_2.png\";s:12:\"coordenada_x\";s:3:\"421\";s:12:\"coordenada_y\";s:2:\"16\";}}'),
	(7568,230,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:101:\"Chaak plantó el sustento, [el augurio es] señorío, es decir, la secuencia en el linaje gobernante.\";s:10:\"texto_maya\";s:38:\"<i>upak\'aj tzeen Chaak, ajawle[l]</i>.\";s:6:\"img_hp\";s:8:\"30_1.png\";s:12:\"coordenada_x\";s:3:\"185\";s:12:\"coordenada_y\";s:2:\"19\";}i:1;a:5:{s:13:\"texto_espanol\";s:64:\"[el dios Jun Ajaw] plantó el alimento, su anuncio es mortandad.\";s:10:\"texto_maya\";s:38:\"<i>upak\'aj tzeen, umu\'uk cham[a]l</i>.\";s:6:\"img_hp\";s:8:\"30_2.png\";s:12:\"coordenada_x\";s:3:\"304\";s:12:\"coordenada_y\";s:2:\"19\";}i:2;a:5:{s:13:\"texto_espanol\";s:58:\"Sak Ik\'(?) plantó el sustento, [el augurio son] semillas.\";s:10:\"texto_maya\";s:44:\"<i>upak\'aj tzeen Sak Ik\'(?), hi\'inaj(?)</i>.\";s:6:\"img_hp\";s:8:\"30_3.png\";s:12:\"coordenada_x\";s:3:\"406\";s:12:\"coordenada_y\";s:2:\"19\";}i:3;a:5:{s:13:\"texto_espanol\";s:60:\"Ik\' Chuwaaj plantó el sustento, [el augurio es] bendición.\";s:10:\"texto_maya\";s:42:\"<i>upak\'a[j] tzeen Ik\' Chuwaaj yutzil</i>.\";s:6:\"img_hp\";s:8:\"30_4.png\";s:12:\"coordenada_x\";s:3:\"548\";s:12:\"coordenada_y\";s:2:\"19\";}}'),
	(7569,231,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:48:\"Kiimil recibe flores, [el augurio es] mortandad.\";s:10:\"texto_maya\";s:38:\"<i>k\'amaw nikte\' Kiimil, cham[a]l</i>.\";s:6:\"img_hp\";s:8:\"31_1.png\";s:12:\"coordenada_x\";s:3:\"272\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:105:\"Itzamna\' Kokaaj Ik\'(?) comió flores, o tal vez Itzamna\' Kokaaj comió flores, [el augurio es] viento(?).\";s:10:\"texto_maya\";s:49:\"<i>umak\'a[j] nikte\' Itzamna[\'] Kokaaj Ik\'(?)</i>.\";s:6:\"img_hp\";s:8:\"31_2.png\";s:12:\"coordenada_x\";s:3:\"444\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7570,232,'repeatable_fields_2','a:2:{i:0;a:5:{s:13:\"texto_espanol\";s:45:\"Kiimil es la craga de Ixik Uh, es su anuncio.\";s:10:\"texto_maya\";s:38:\"<i>[Kiimil] ukuch Ixik Uh, umu\'uk</i>.\";s:6:\"img_hp\";s:8:\"32_1.png\";s:12:\"coordenada_x\";s:3:\"304\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:60:\"pepitas(?) son la carga de Ixik Uh, [el augurio son] elotes.\";s:10:\"texto_maya\";s:39:\"<i>[saa]k(?) [ukuch] Ixik Uh, ahan</i>.\";s:6:\"img_hp\";s:8:\"32_2.png\";s:12:\"coordenada_x\";s:3:\"431\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7571,233,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:31:\"...es su pago o es su esposa...\";s:6:\"img_hp\";s:8:\"33_1.png\";s:10:\"texto_maya\";s:35:\"<i>[...] yat[aa]l / yatan [...]</i>\";s:12:\"coordenada_x\";s:3:\"333\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7572,234,'repeatable_fields_2','a:4:{i:0;a:5:{s:13:\"texto_espanol\";s:56:\"Chaak es la carga de Ixik Uh, [el augurio es] señorío.\";s:10:\"texto_maya\";s:38:\"<i>Chaak ukuch Ixik Uh, ajawle[l]</i>.\";s:6:\"img_hp\";s:8:\"34_1.png\";s:12:\"coordenada_x\";s:3:\"212\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:57:\"Kiimil es la carga de Ixik Uh, [el augurio es] mortandad.\";s:10:\"texto_maya\";s:38:\"<i>Kiimil ukuch Ixik Uh, cham[a]l</i>.\";s:6:\"img_hp\";s:8:\"34_2.png\";s:12:\"coordenada_x\";s:3:\"344\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:68:\"Itzamna\' Kokaaj es la carga de Ixik Uh, [el augurio son] pepitas(?).\";s:10:\"texto_maya\";s:52:\"<i>Itzamna[\'] Kokaaj ukuch Ixik Uh, saak[i]l(?)</i>.\";s:6:\"img_hp\";s:8:\"34_3.png\";s:12:\"coordenada_x\";s:3:\"499\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:64:\"Jun Lajun Talaan es la carga de Ixik Uh [el augurio es] ruin(?).\";s:10:\"texto_maya\";s:47:\"<i>Jun Lajun Talaan ukuch Ixik Uh, k\'as(?)</i>.\";s:6:\"img_hp\";s:8:\"34_4.png\";s:12:\"coordenada_x\";s:3:\"499\";s:12:\"coordenada_y\";s:2:\"96\";}}'),
	(7573,235,'repeatable_fields_2','a:6:{i:0;a:5:{s:13:\"texto_espanol\";s:54:\"Oxlajun Muwaan es el augurio de Ixik Uh, es su anuncio\";s:10:\"texto_maya\";s:42:\"<i>Oxlajun Muwaan umuut Ixik Uh umu\'uk</i>\";s:6:\"img_hp\";s:8:\"35_1.png\";s:12:\"coordenada_x\";s:3:\"127\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:46:\"el quetzal es el anuncio Ixik Uh, mucha comida\";s:10:\"texto_maya\";s:38:\"<i>k\'uk\' umu\'uk Ixik Uh ox wi\'[il]</i>\";s:6:\"img_hp\";s:8:\"35_2.png\";s:12:\"coordenada_x\";s:3:\"259\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:54:\"la guacamaya es el presagio de Sak Ixik, es su anuncio\";s:10:\"texto_maya\";s:35:\"<i>mo\'o\' umuut Sak Ixik, umu\'uk</i>\";s:6:\"img_hp\";s:8:\"35_3.png\";s:12:\"coordenada_x\";s:3:\"384\";s:12:\"coordenada_y\";s:1:\"1\";}i:3;a:5:{s:13:\"texto_espanol\";s:50:\"es la cotinga de Ixik Uh, su presagio es señorío\";s:10:\"texto_maya\";s:38:\"<i>yaxuun Ixik Uh, umuut ajawle[l]</i>\";s:6:\"img_hp\";s:8:\"35_4.png\";s:12:\"coordenada_x\";s:3:\"523\";s:12:\"coordenada_y\";s:1:\"1\";}i:4;a:5:{s:13:\"texto_espanol\";s:53:\"zopilote es el presagio de Ixik Uh, [augurio] ruin(?)\";s:10:\"texto_maya\";s:35:\"<i>k\'uuch umuut Ixik Uh k\'as(?)</i>\";s:6:\"img_hp\";s:8:\"35_5.png\";s:12:\"coordenada_x\";s:3:\"595\";s:12:\"coordenada_y\";s:1:\"1\";}i:5;a:5:{s:13:\"texto_espanol\";s:67:\"pavo silvestre es el vaticinio de Ixik Uh, [el augurio es] alimento\";s:10:\"texto_maya\";s:38:\"<i>kutz umuwa[k] Ixik Uh, o\'och(?)</i>\";s:6:\"img_hp\";s:8:\"35_6.png\";s:12:\"coordenada_x\";s:3:\"659\";s:12:\"coordenada_y\";s:1:\"1\";}}'),
	(7574,236,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:65:\"parte del nombre del anciano dios N o Ho\' Tuun [Itzam]-Pawahtuun.\";s:6:\"img_hp\";s:8:\"36_1.png\";s:10:\"texto_maya\";s:24:\"<i>Ho\' Tuun [Itzam].</i>\";s:12:\"coordenada_x\";s:3:\"354\";s:12:\"coordenada_y\";s:2:\"14\";}}'),
	(7582,237,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:39:\"Ixik Uh carga fuego, [augurio] ruin(?).\";s:6:\"img_hp\";s:8:\"37_1.png\";s:10:\"texto_maya\";s:40:\"<i>[ukuch k\'ahk\'], k\'as(?), Ixik Uh</i>.\";s:12:\"coordenada_x\";s:3:\"354\";s:12:\"coordenada_y\";s:2:\"14\";}}'),
	(7583,238,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:52:\"es la carga de Jun Lajun Talaan, su anuncio es malo.\";s:6:\"img_hp\";s:8:\"38_1.png\";s:10:\"texto_maya\";s:44:\"<i>ukuch Jun Lajun Talaan, umu\'uk lobal</i>.\";s:12:\"coordenada_x\";s:3:\"354\";s:12:\"coordenada_y\";s:2:\"14\";}}'),
	(7593,239,'repeatable_fields_2','a:6:{i:0;a:5:{s:13:\"texto_espanol\";s:69:\"cotinga es el pájaro/presagio de Ixik Uh, [el augurio es] señorío.\";s:10:\"texto_maya\";s:39:\"<i>yaxuun umuut Ixik Uh, ajawle[l]</i>.\";s:6:\"img_hp\";s:8:\"39_1.png\";s:12:\"coordenada_x\";s:2:\"57\";s:12:\"coordenada_y\";s:1:\"1\";}i:1;a:5:{s:13:\"texto_espanol\";s:65:\"mono araña es el presagio de Ixik Uh, [el augurio] es señorío.\";s:10:\"texto_maya\";s:39:\"<i>maax [u]muut Ixik Uh, ajawle[l]</i>.\";s:6:\"img_hp\";s:8:\"39_2.png\";s:12:\"coordenada_x\";s:3:\"191\";s:12:\"coordenada_y\";s:1:\"1\";}i:2;a:5:{s:13:\"texto_espanol\";s:46:\"perro es el presagio de Ixik Uh, mucha comida.\";s:10:\"texto_maya\";s:38:\"<i>tzul umuut Ixik Uh, ox wi\'[il]</i>.\";s:6:\"img_hp\";s:8:\"39_3.png\";s:12:\"coordenada_x\";s:3:\"178\";s:12:\"coordenada_y\";s:2:\"88\";}i:3;a:5:{s:13:\"texto_espanol\";s:61:\"Kiimil es el presagio de Sak Ixik, [el augurio] es mortandad.\";s:10:\"texto_maya\";s:39:\"<i>Kiimil umuut Sak Ixik, cham[a]l</i>.\";s:6:\"img_hp\";s:8:\"39_4.png\";s:12:\"coordenada_x\";s:3:\"351\";s:12:\"coordenada_y\";s:2:\"20\";}i:4;a:5:{s:13:\"texto_espanol\";s:72:\"Itzamna\' Kokaaj es el presagio de Sak Ixik, [el augurio] son pepitas(?).\";s:10:\"texto_maya\";s:52:\"<i>Itzamna[\'] Kokaaj umuut Sak Ixik saak[i]l(?)</i>.\";s:6:\"img_hp\";s:8:\"39_5.png\";s:12:\"coordenada_x\";s:3:\"501\";s:12:\"coordenada_y\";s:2:\"20\";}i:5;a:5:{s:13:\"texto_espanol\";s:56:\"Oxlajun Muwaan es el presagio de Ixik Uh, es su anuncio.\";s:10:\"texto_maya\";s:44:\"<i>Oxlajun Muwaan umuut Ixik Uh, umu\'uk</i>.\";s:6:\"img_hp\";s:8:\"39_6.png\";s:12:\"coordenada_x\";s:3:\"645\";s:12:\"coordenada_y\";s:2:\"20\";}}'),
	(7614,226,'repeatable_fields_2','a:3:{i:0;a:5:{s:13:\"texto_espanol\";s:50:\"la muerte es la carga de Ixik Uh, es su mortandad.\";s:6:\"img_hp\";s:8:\"40_1.png\";s:10:\"texto_maya\";s:41:\"<i>ukiimil uchuch Ixik Uh, ucham[a]l</i>.\";s:12:\"coordenada_x\";s:3:\"177\";s:12:\"coordenada_y\";s:2:\"10\";}i:1;a:5:{s:13:\"texto_espanol\";s:71:\"la carga de Itzamna\' Kokaaj Ixik Uh es riqueza (lo verde, lo amarillo).\";s:6:\"img_hp\";s:8:\"40_2.png\";s:10:\"texto_maya\";s:54:\"<i>uya\'ax [u]k\'an ukuch Itzamna[\'] Kokaaj Ixik Uh</i>.\";s:12:\"coordenada_x\";s:3:\"386\";s:12:\"coordenada_y\";s:2:\"10\";}i:2;a:5:{s:13:\"texto_espanol\";s:39:\"muy es la carga, el anuncio de Ixik Uh.\";s:6:\"img_hp\";s:8:\"40_3.png\";s:10:\"texto_maya\";s:34:\"<i>muy ukuch, umu\'uk, Ixik Uh</i>.\";s:12:\"coordenada_x\";s:3:\"536\";s:12:\"coordenada_y\";s:2:\"10\";}}'),
