	(7853,867,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:175:\"En esta página sólo apreciamos la primer viñeta del almanaque, donde aparece Chaak posado sobre un árbol y portando lo que Thompson (1972) creía es una bolsa de semillas.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
