	(8071,1058,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:239:\"La escena central representa a <i>Chaak</i> posado sobre un perro muerto con la lengua salida. Tal vez falleció por sed. El dios y el can se posan sobre otro árbol, que de acuerdo con el texto jeroglífico, es el árbol blanco del norte.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
