	(8212,1061,'repeatable_fields_2','a:1:{i:0;a:5:{s:13:\"texto_espanol\";s:265:\"En la escena central <i>Chaak</i> se encuentra ricamente ataviado por medio de una capa o chal cuyos bordes parecen estar hechos con plumaria. Esta vez se sienta sobre una senda o camino, indicada mediante la convención conceptual de una banda con huellas humanas.\";s:10:\"texto_maya\";s:0:\"\";s:6:\"img_hp\";s:0:\"\";s:12:\"coordenada_x\";s:0:\"\";s:12:\"coordenada_y\";s:0:\"\";}}'),
