	(237,1,'2017-04-07 07:48:07','2017-04-07 13:48:07','<p>Davoust (1997) hizo un esfuerzo supremo para reconstruir el dañado augurio, sigo sus lecturas pero actualizándolas.</p>','Augurios -37','','publish','closed','closed','','augurios-37','','','2017-04-26 10:23:51','2017-04-26 16:23:51','',0,'http://localhost:8888/CodiceDressdeWeb/?post_type=hotspots&#038;p=237',0,'hotspots','',0),
